import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.BO1WGGxE.js";const h=JSON.parse('{"title":"What is TypeORM Query Scopes?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-typeorm-query-scopes.md","filePath":"guide/what-is-typeorm-query-scopes.md"}'),r={name:"guide/what-is-typeorm-query-scopes.md"};function l(s,e,n,p,d,c){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="what-is-typeorm-query-scopes" tabindex="-1">What is TypeORM Query Scopes? <a class="header-anchor" href="#what-is-typeorm-query-scopes" aria-label="Permalink to &quot;What is TypeORM Query Scopes?&quot;">​</a></h1><p>TypeORM Query Scopes is a package that brings Sequelize-style scopes to TypeORM, allowing you to define reusable query patterns using decorators.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>When working with TypeORM, you often find yourself repeating the same query patterns:</p><ul><li>Same where conditions across multiple files</li><li>Repeated select field lists</li><li>Common relation loading patterns</li><li>Consistent ordering logic</li></ul><p>This leads to:</p><ul><li>Code duplication</li><li>Maintenance nightmares</li><li>Inconsistent query logic</li><li>Verbose, hard-to-read code</li></ul><h2 id="the-solution" tabindex="-1">The Solution <a class="header-anchor" href="#the-solution" aria-label="Permalink to &quot;The Solution&quot;">​</a></h2><p>TypeORM Scopes lets you define query patterns once and reuse them everywhere:</p><ul><li><strong>Define once</strong> - Use decorators to define scopes on your entities</li><li><strong>Use everywhere</strong> - Apply scopes with a simple, chainable API</li><li><strong>Compose freely</strong> - Combine multiple scopes intelligently</li><li><strong>Stay type-safe</strong> - Full TypeScript support with IDE autocomplete</li></ul><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><h3 id="scopes" tabindex="-1">Scopes <a class="header-anchor" href="#scopes" aria-label="Permalink to &quot;Scopes&quot;">​</a></h3><p>A scope is a reusable query pattern that can include:</p><ul><li><strong>where</strong> - Filter conditions</li><li><strong>select</strong> - Field selection</li><li><strong>relations</strong> - Relation loading</li><li><strong>order</strong> - Sorting logic</li><li><strong>skip/take</strong> - Pagination</li></ul><h3 id="default-scopes" tabindex="-1">Default Scopes <a class="header-anchor" href="#default-scopes" aria-label="Permalink to &quot;Default Scopes&quot;">​</a></h3><p>Automatically applied to all queries. Perfect for:</p><ul><li>Soft deletes</li><li>Multi-tenancy</li><li>Active/inactive filtering</li></ul><h3 id="named-scopes" tabindex="-1">Named Scopes <a class="header-anchor" href="#named-scopes" aria-label="Permalink to &quot;Named Scopes&quot;">​</a></h3><p>Explicitly applied when needed. Great for:</p><ul><li>Role-based filtering</li><li>Status filtering</li><li>Common query patterns</li></ul><h3 id="function-scopes" tabindex="-1">Function Scopes <a class="header-anchor" href="#function-scopes" aria-label="Permalink to &quot;Function Scopes&quot;">​</a></h3><p>Dynamic scopes that accept parameters:</p><ul><li>Search by field</li><li>Date range filtering</li><li>Custom logic</li></ul><h2 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h2><h3 id="for-developers" tabindex="-1">For Developers <a class="header-anchor" href="#for-developers" aria-label="Permalink to &quot;For Developers&quot;">​</a></h3><ul><li><strong>Less Code</strong> - Reduce query code by up to 60%</li><li><strong>Better Readability</strong> - Clean, declarative syntax</li><li><strong>Faster Development</strong> - Reuse instead of rewrite</li><li><strong>Type Safety</strong> - Catch errors at compile-time</li></ul><h3 id="for-teams" tabindex="-1">For Teams <a class="header-anchor" href="#for-teams" aria-label="Permalink to &quot;For Teams&quot;">​</a></h3><ul><li><strong>Consistency</strong> - Centralized query logic</li><li><strong>Maintainability</strong> - Change once, apply everywhere</li><li><strong>Onboarding</strong> - New developers understand queries faster</li><li><strong>Quality</strong> - Tested, reusable patterns</li></ul><h3 id="for-projects" tabindex="-1">For Projects <a class="header-anchor" href="#for-projects" aria-label="Permalink to &quot;For Projects&quot;">​</a></h3><ul><li><strong>Scalability</strong> - Easy to add new query patterns</li><li><strong>Flexibility</strong> - Works alongside existing code</li><li><strong>Performance</strong> - Zero runtime overhead</li><li><strong>Reliability</strong> - Comprehensive test coverage</li></ul><h2 id="comparison-with-sequelize" tabindex="-1">Comparison with Sequelize <a class="header-anchor" href="#comparison-with-sequelize" aria-label="Permalink to &quot;Comparison with Sequelize&quot;">​</a></h2><p>If you&#39;ve used Sequelize, TypeORM Scopes will feel familiar:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Sequelize</th><th>TypeORM Scopes</th></tr></thead><tbody><tr><td>Default scope</td><td>✅</td><td>✅</td></tr><tr><td>Named scopes</td><td>✅</td><td>✅</td></tr><tr><td>Function scopes</td><td>✅</td><td>✅</td></tr><tr><td>Scope merging</td><td>✅</td><td>✅</td></tr><tr><td>Type safety</td><td>❌</td><td>✅</td></tr><tr><td>Decorator-based</td><td>❌</td><td>✅</td></tr></tbody></table><h2 id="when-to-use" tabindex="-1">When to Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to Use&quot;">​</a></h2><p>TypeORM Scopes is perfect for:</p><ul><li>✅ Projects with repeated query patterns</li><li>✅ Applications with complex filtering logic</li><li>✅ Multi-tenant applications</li><li>✅ APIs with consistent response formats</li><li>✅ Teams wanting better code organization</li></ul><h2 id="when-not-to-use" tabindex="-1">When Not to Use <a class="header-anchor" href="#when-not-to-use" aria-label="Permalink to &quot;When Not to Use&quot;">​</a></h2><p>Consider alternatives if:</p><ul><li>❌ You have very simple queries</li><li>❌ Each query is completely unique</li><li>❌ You prefer query builders over repositories</li><li>❌ You&#39;re not using TypeORM 0.3+</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Ready to get started?</p><ul><li><a href="/typeorm-query-scopes/guide/getting-started.html">Installation &amp; Setup</a></li><li><a href="/typeorm-query-scopes/guide/why-scopes.html">Learn Why Scopes Matter</a></li><li><a href="/typeorm-query-scopes/examples/basic.html">Explore Examples</a></li></ul>',42)])])}const y=t(r,[["render",l]]);export{h as __pageData,y as default};
